import os
import zipfile
import shutil
import threading
import numpy as np
import tensorflow as tf
from flask import Flask, request, jsonify, send_from_directory
from werkzeug.utils import secure_filename

# --- Configuration ---
UPLOAD_FOLDER = 'data/uploads'
TRAIN_DATA_DIR = 'data/train'
MODEL_DIR = 'models'
ALLOWED_EXTENSIONS = {'zip'}
IMAGE_SIZE = (128, 128)
BATCH_SIZE = 32
EPOCHS = 10  # Reduced for example, increase for real training

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

# Ensure directories exist
os.makedirs(UPLOAD_FOLDER, exist_ok=True)
os.makedirs(TRAIN_DATA_DIR, exist_ok=True)
os.makedirs(MODEL_DIR, exist_ok=True)

# Global variables for training status and model
is_training = False
current_model = None
current_model_path = os.path.join(MODEL_DIR, 'community_model.h5')
class_names = [] # To store the list of class names after data loading

# --- Helper Functions ---
def allowed_file(filename):
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def load_or_create_model(num_classes):
    global current_model
    if os.path.exists(current_model_path):
        print(f"Loading existing model from {current_model_path}")
        try:
            current_model = tf.keras.models.load_model(current_model_path)
            # Ensure the output layer matches the current number of classes
            if current_model.layers[-1].units != num_classes:
                print(f"Model output layer mismatch: {current_model.layers[-1].units} vs {num_classes}. Rebuilding top.")
                # Rebuild the top layers
                base_model = tf.keras.Model(inputs=current_model.input, outputs=current_model.layers[-2].output)
                x = base_model.output
                predictions = tf.keras.layers.Dense(num_classes, activation='softmax')(x)
                current_model = tf.keras.Model(inputs=base_model.input, outputs=predictions)
                current_model.compile(optimizer='adam',
                                      loss='sparse_categorical_crossentropy',
                                      metrics=['accuracy'])
        except Exception as e:
            print(f"Error loading model: {e}. Creating a new model.")
            current_model = None # Fallback to creating new model
    
    if current_model is None:
        print("Creating a new model.")
        model = tf.keras.Sequential([
            tf.keras.layers.Rescaling(1./255, input_shape=(IMAGE_SIZE[0], IMAGE_SIZE[1], 3)),
            tf.keras.layers.Conv2D(32, (3, 3), activation='relu'),
            tf.keras.layers.MaxPooling2D((2, 2)),
            tf.keras.layers.Conv2D(64, (3, 3), activation='relu'),
            tf.keras.layers.MaxPooling2D((2, 2)),
            tf.keras.layers.Conv2D(128, (3, 3), activation='relu'),
            tf.keras.layers.MaxPooling2D((2, 2)),
            tf.keras.layers.Flatten(),
            tf.keras.layers.Dense(128, activation='relu'),
            tf.keras.layers.Dense(num_classes, activation='softmax')
        ])
        model.compile(optimizer='adam',
                      loss='sparse_categorical_crossentropy',
                      metrics=['accuracy'])
        current_model = model
    return current_model

def train_model_background():
    global is_training, current_model, class_names

    if is_training:
        print("Training already in progress.")
        return

    is_training = True
    print("Starting training process...")

    try:
        # Load data from the aggregated TRAIN_DATA_DIR
        if not os.path.exists(TRAIN_DATA_DIR) or not os.listdir(TRAIN_DATA_DIR):
            print("No training data available. Please upload datasets.")
            is_training = False
            return

        train_ds = tf.keras.utils.image_dataset_from_directory(
            TRAIN_DATA_DIR,
            labels='inferred',
            label_mode='int',
            image_size=IMAGE_SIZE,
            interpolation='nearest',
            batch_size=BATCH_SIZE,
            shuffle=True
        )

        if not train_ds:
            print("Failed to load training dataset.")
            is_training = False
            return

        class_names = train_ds.class_names
        num_classes = len(class_names)
        print(f"Found {num_classes} classes: {class_names}")

        # Configure dataset for performance
        AUTOTUNE = tf.data.AUTOTUNE
        train_ds = train_ds.cache().prefetch(buffer_size=AUTOTUNE)

        # Load or create model
        model = load_or_create_model(num_classes)
        model.summary()

        # Train the model
        history = model.fit(
            train_ds,
            epochs=EPOCHS
        )

        # Save the trained model
        model.save(current_model_path)
        print(f"Model trained and saved to {current_model_path}")
        current_model = model # Update the global model instance

    except Exception as e:
        print(f"Error during training: {e}")
    finally:
        is_training = False
        print("Training process finished.")

